import{_ as e,o as a,c as r,ag as s}from"./chunks/framework.6MCaaFDc.js";const g=JSON.parse('{"title":"Algorithms","description":"","frontmatter":{"title":"Algorithms","parent":"Practical (Paper 1)","nav_order":1,"has_children":true},"headers":[],"relativePath":"practical/algorithms/index.md","filePath":"practical/algorithms/index.md"}'),o={name:"practical/algorithms/index.md"};function i(n,t,d,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="algorithms" tabindex="-1">Algorithms <a class="header-anchor" href="#algorithms" aria-label="Permalink to &quot;Algorithms&quot;">​</a></h1><p>Before writing a single line of code, a good programmer designs a solution. Algorithms are step-by-step instructions for solving a problem — they can be expressed as pseudocode, flowcharts or structured English. Mastering algorithm design makes everything else in programming easier.</p><h2 id="what-s-in-this-section" tabindex="-1">What&#39;s in this section <a class="header-anchor" href="#what-s-in-this-section" aria-label="Permalink to &quot;What&#39;s in this section&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>What you&#39;ll learn</th></tr></thead><tbody><tr><td><a href="./sequential.html">Sequential Structures</a></td><td>Algorithms that execute steps in order — input, process, output patterns</td></tr><tr><td><a href="./decision.html">Decision Structures</a></td><td>IF-THEN-ELSE, CASE statements — making choices in an algorithm</td></tr><tr><td><a href="./repetition.html">Repetition Structures</a></td><td>FOR, WHILE, REPEAT-UNTIL loops — repeating steps efficiently</td></tr><tr><td><a href="./classic-problems.html">Classic Problems</a></td><td>Search algorithms, sorting algorithms, totals, counters and common patterns</td></tr></tbody></table><h2 id="pseudocode-vs-flowcharts" tabindex="-1">Pseudocode vs Flowcharts <a class="header-anchor" href="#pseudocode-vs-flowcharts" aria-label="Permalink to &quot;Pseudocode vs Flowcharts&quot;">​</a></h2><p>South African IT examinations may ask you to write <strong>pseudocode</strong> or draw/interpret a <strong>flowchart</strong>. Both represent the same logic in different ways:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Strengths</th></tr></thead><tbody><tr><td>Pseudocode</td><td>Quick to write, easy to convert to code, language-independent</td></tr><tr><td>Flowchart</td><td>Visually clear, great for showing branches and loops</td></tr></tbody></table><h2 id="caps-alignment" tabindex="-1">CAPS alignment <a class="header-anchor" href="#caps-alignment" aria-label="Permalink to &quot;CAPS alignment&quot;">​</a></h2><p>Algorithms appear in both <strong>Paper 1</strong> (design and implementation) and <strong>Paper 2</strong> (tracing and explaining) across Grades 10–12. In Paper 1, algorithm design is usually the first question and sets up the Delphi coding that follows.</p>',9)])])}const m=e(o,[["render",i]]);export{g as __pageData,m as default};
